package com.parkflow.mall.reservation;
import com.parkflow.mall.reservation.dto.CreateReservationRequest;import com.parkflow.mall.reservation.model.VehicleType;import com.parkflow.mall.reservation.repository.InMemoryReservationRepository;import com.parkflow.mall.reservation.service.ReservationService;import java.time.Instant;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;
class ReservationServiceExpiryTests { @Test void expiredReservationReleasesCapacityAndPlate() {ReservationService service=new ReservationService(new InMemoryReservationRepository(),1,1,0);CreateReservationRequest request=new CreateReservationRequest("59A1-88888",VehicleType.MOTORBIKE,Instant.now().plusSeconds(60),Instant.now().plusSeconds(600),null,null);String code=service.create(request).reservationCode();assertEquals(1,service.expire().expiredCount());assertEquals("EXPIRED",service.get(code).status().name());assertDoesNotThrow(()->service.create(request));} }
